export default function BookmarkSliceTransition(){const [saved,setSaved]=useState(false);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><div className="flex items-center justify-between gap-3"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">bookmark slice</p><button type="button" aria-expanded={saved} onClick={()=>setSaved(!saved)} className="min-h-11 rounded-xl border border-[#111] px-3 text-sm font-black outline-offset-3 focus-visible:outline focus-visible:outline-3 focus-visible:outline-[#111]">{saved?"Show summary":"Show saved note"}</button></div><div className="relative mt-4 overflow-hidden rounded-2xl bg-[#f4f5f6] p-4"><motion.i aria-hidden animate={{x:saved?220:0}} transition={reduced?{duration:0}:{type:"spring",stiffness:280,damping:28}} className="absolute inset-y-0 left-0 w-3 bg-[#f5e642]"/><AnimatePresence mode="wait"><motion.p key={String(saved)} initial={{opacity:0,y:reduced?0:10}} animate={{opacity:1,y:0}} exit={{opacity:0,y:reduced?0:-8}} transition={{duration:.18}} className="pl-2 text-sm text-[#4a4a4f]"><b className="text-[#111]">{saved?"Saved note:":"Summary:"}</b> {saved?"Keep the decision visible at handoff.":"The proposal is ready for a concise review."}</motion.p></AnimatePresence></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Viewing {saved?"saved note":"summary"}.</p></section>}
